1	import { useCallback, useEffect, useRef, useState } from "react";
2	import { useTransport } from "@audio/use-transport";
3	import { useDawStore } from "@state/index";
4	import type { TrackType } from "@state/track/types";
5	import { BpmInput } from "./BpmInput";
6	import { CursorDisplay } from "./CursorDisplay";
7	import styles from "./TransportBar.module.css";
8	
9	const TRACK_PRESETS: {
10	  label: string;
11	  type: TrackType;
12	  color: string;
13	  namePrefix: string;
14	}[] = [
15	  {
16	    label: "Audio Track",
17	    type: "audio",
18	    color: "#4A90D9",
19	    namePrefix: "Audio",
20	  },
21	  {
22	    label: "Instrument Track",
23	    type: "instrument",
24	    color: "#D94A90",
25	    namePrefix: "Synth",
26	  },
27	  { label: "Drum Track", type: "drum", color: "#FF6B35", namePrefix: "808" },
28	];
29	
30	export function TransportBar(): React.JSX.Element {
31	  const transport = useTransport();
32	  const transportState = useDawStore((s) => s.transportState);
33	  const bpm = useDawStore((s) => s.bpm);
34	  const loopEnabled = useDawStore((s) => s.loopEnabled);
35	  const setLoop = useDawStore((s) => s.setLoop);
36	  const addTrack = useDawStore((s) => s.addTrack);
37	  const setSelectedTrackIds = useDawStore((s) => s.setSelectedTrackIds);
38	  const [metronomeOn, setMetronomeOn] = useState(false);
39	  const [addMenuOpen, setAddMenuOpen] = useState(false);
40	  const addMenuRef = useRef<HTMLDivElement>(null);
41	
42	  const handleLoopToggle = useCallback((): void => {
43	    setLoop(!loopEnabled);
44	  }, [loopEnabled, setLoop]);
45	
46	  const handleMetronomeToggle = useCallback((): void => {
47	    const next = !metronomeOn;
48	    setMetronomeOn(next);
49	    transport.setMetronomeEnabled(next);
50	  }, [metronomeOn, transport]);
51	
52	  const handleBpmChange = useCallback(
53	    (newBpm: number): void => {
54	      transport.setBpm(newBpm);
55	    },
56	    [transport],
57	  );
58	
59	  const handleAddTrack = useCallback(
60	    (type: TrackType, color: string, namePrefix: string): void => {
61	      const existing = useDawStore
62	        .getState()
63	        .tracks.filter((t) => t.type === type);
64	      const maxNum = existing.reduce((max, t) => {
65	        if (t.name.startsWith(namePrefix + " ")) {
66	          const num = parseInt(t.name.slice(namePrefix.length + 1), 10);
67	          if (!Number.isNaN(num)) return Math.max(max, num);
68	        }
69	        return max;
70	      }, 0);
71	      const id = crypto.randomUUID();
72	      addTrack({
73	        id,
74	        name: `${namePrefix} ${String(maxNum + 1)}`,
75	        type,
76	        color,
77	        muted: false,
78	        solo: false,
79	        armed: false,
80	        soloIsolate: false,
81	        volume: 1,
82	        pan: 0,
83	        clipIds: [],
84	      });
85	      setSelectedTrackIds([id]);
86	      setAddMenuOpen(false);
87	    },
88	    [addTrack, setSelectedTrackIds],
89	  );
90	
91	  // Close menu on outside click or Escape key
92	  useEffect(() => {
93	    if (!addMenuOpen) return;
94	    const handleClick = (e: MouseEvent): void => {
95	      if (
96	        addMenuRef.current &&
97	        !addMenuRef.current.contains(e.target as Node)
98	      ) {
99	        setAddMenuOpen(false);
100	      }
101	    };
102	    const handleKeyDown = (e: KeyboardEvent): void => {
103	      if (e.key === "Escape") {
104	        setAddMenuOpen(false);
105	      }
106	    };
107	    document.addEventListener("mousedown", handleClick);
108	    document.addEventListener("keydown", handleKeyDown);
109	    return () => {
110	      document.removeEventListener("mousedown", handleClick);
111	      document.removeEventListener("keydown", handleKeyDown);
112	    };
113	  }, [addMenuOpen]);
114	
115	  const isPlaying = transportState === "playing";
116	  const clock = transport.getClock();
117	  const tempoMap = clock?.getTempoMap() ?? null;
118	
119	  return (
120	    <header data-testid="toolbar" className={styles["transportBar"]}>
121	      <span className={styles["brand"]}>BRUTALWAV</span>
122	
123	      <div className={styles["addTrackWrapper"]} ref={addMenuRef}>
124	        <button
125	          type="button"
126	          className={styles["transportBtn"]}
127	          aria-label="Add Track"
128	          aria-haspopup="menu"
129	          aria-expanded={addMenuOpen}
130	          onClick={() => {
131	            setAddMenuOpen((prev) => !prev);
132	          }}
133	        >
134	          +
135	        </button>
136	        {addMenuOpen && (
137	          <div className={styles["addTrackMenu"]} role="menu">
138	            {TRACK_PRESETS.map((preset) => (
139	              <button
140	                key={preset.type}
141	                type="button"
142	                role="menuitem"
143	                className={styles["addTrackMenuItem"]}
144	                onClick={() => {
145	                  handleAddTrack(preset.type, preset.color, preset.namePrefix);
146	                }}
147	              >
148	                <span
149	                  className={styles["trackColorDot"]}
150	                  style={{ backgroundColor: preset.color }}
151	                />
152	                {preset.label}
153	              </button>
154	            ))}
155	          </div>
156	        )}
157	      </div>
158	
159	      <div className={styles["spacer"]} />
160	
161	      <div className={styles["controls"]}>
162	        <span className={styles["label"]}>BPM</span>
163	        <BpmInput value={bpm} onChange={handleBpmChange} />
164	
165	        <span className={styles["label"]}>4/4</span>
166	
167	        <button
168	          type="button"
169	          className={styles["transportBtn"]}
170	          aria-pressed={isPlaying}
171	          aria-label="Play"
172	          onClick={() => {
173	            transport.play();
174	          }}
175	        >
176	          {"\u25B6"}
177	        </button>
178	
179	        <button
180	          type="button"
181	          className={styles["transportBtn"]}
182	          aria-label="Stop"
183	          onClick={() => {
184	            transport.stop();
185	          }}
186	        >
187	          {"\u25A0"}
188	        </button>
189	
190	        <CursorDisplay
191	          transportSAB={transport.getTransportSAB()}
192	          tempoMap={tempoMap}
193	        />
194	
195	        <button
196	          type="button"
197	          role="switch"
198	          aria-checked={loopEnabled}
199	          aria-label="Loop"
200	          className={styles["transportBtn"]}
201	          data-active={loopEnabled}
202	          onClick={handleLoopToggle}
203	        >
204	          LOOP
205	        </button>
206	
207	        <div className={styles["metronomeToggle"]}>
208	          <button
209	            type="button"
210	            role="switch"
211	            aria-checked={metronomeOn}
212	            aria-label="Metronome"
213	            className={styles["transportBtn"]}
214	            data-active={metronomeOn}
215	            onClick={handleMetronomeToggle}
216	          >
217	            MET
218	          </button>
219	        </div>
220	      </div>
221	
222	      <span
223	        className={styles["shortcutHint"]}
224	        title="Keyboard Shortcuts (Shift+?)"
225	      >
226	        ?
227	      </span>
228	    </header>
229	  );
230	}
