1	/**
2	 * Types for the bounce/export system.
3	 * Offline rendering of the session to WAV file.
4	 *
5	 * EARS: R-EVT-14, NFR-17
6	 * Exports: BounceEngine, BounceProgress
7	 */
8	
9	import type {
10	  AudioClipModel,
11	  MidiClipModel,
12	  TrackModel,
13	} from "@state/track/types";
14	import type { AutomationLane } from "@audio/automation/automation-types";
15	import type {
16	  DrumInstrumentId,
17	  DrumInstrumentParams,
18	} from "@audio/drum-machine/drum-types";
19	import type { SynthParameterMap } from "@audio/synth/synth-types";
20	
21	/** Bounce range: either full session or a specific time region */
22	export type BounceRange =
23	  | { readonly type: "full" }
24	  | { readonly type: "region"; readonly start: number; readonly end: number };
25	
26	/** Per-track instrument configuration for offline rendering */
27	export type TrackInstrumentConfig =
28	  | { readonly type: "audio" }
29	  | {
30	      readonly type: "synth";
31	      readonly params: SynthParameterMap;
32	    }
33	  | {
34	      readonly type: "drums";
35	      readonly samples: ReadonlyMap<DrumInstrumentId, AudioBuffer>;
36	      readonly params: ReadonlyMap<DrumInstrumentId, DrumInstrumentParams>;
37	    };
38	
39	/** Options for a bounce operation */
40	export type BounceOptions = {
41	  readonly sampleRate: number;
42	  readonly bitDepth: 16 | 24 | 32;
43	  readonly range: BounceRange;
44	  readonly tracks: readonly TrackModel[];
45	  readonly clips: Readonly<Record<string, AudioClipModel | MidiClipModel>>;
46	  readonly automationLanes: readonly AutomationLane[];
47	  readonly masterLevel: number;
48	  readonly getBuffer: (sourceId: string) => AudioBuffer | undefined;
49	  readonly instruments: ReadonlyMap<string, TrackInstrumentConfig>;
50	};
51	
52	/** Progress update during bounce */
53	export type BounceProgress = {
54	  readonly phase: "preparing" | "rendering" | "encoding" | "complete";
55	  readonly progress: number; // 0..1
56	  readonly renderedSeconds: number;
57	  readonly totalSeconds: number;
58	};
59	
60	/** Result of a successful bounce */
61	export type BounceResult = {
62	  readonly blob: Blob;
63	  readonly duration: number;
64	  readonly sampleRate: number;
65	  readonly channels: number;
66	};
67	
68	/** Bounce engine interface */
69	export type BounceEngine = {
70	  /** Start a bounce operation. Returns async iterable of progress updates. */
71	  bounce(options: BounceOptions): AsyncGenerator<BounceProgress, BounceResult>;
72	  /** Cancel the current bounce operation. */
73	  cancel(): void;
74	};
