1	/**
2	 * Bounce/export engine: offline rendering of the session to WAV.
3	 *
4	 * Renders the full audio graph in an OfflineAudioContext:
5	 * - Mixer channel strips + master bus + brickwall limiter
6	 * - Audio clip scheduling
7	 * - Pre-rendered synth MIDI clips
8	 * - Drum machine triggers
9	 * - Automation curves
10	 *
11	 * Cooperative cancellation via internal flag.
12	 * Progress reporting via async generator.
13	 *
14	 * EARS: R-EVT-14, NFR-17
15	 */
16	
17	import type {
18	  AudioClipModel,
19	  MidiClipModel,
20	  TrackModel,
21	  ClipModel,
22	} from "@state/track/types";
23	import { isAudioClip, isMidiClip } from "@state/track/types";
24	import type {
25	  BounceEngine,
26	  BounceOptions,
27	  BounceProgress,
28	  BounceResult,
29	  TrackInstrumentConfig,
30	} from "./types";
31	import type { AutomationLane } from "@audio/automation/automation-types";
32	import type { DrumInstrumentId } from "@audio/drum-machine/drum-types";
33	import {
34	  evaluateCurve,
35	  denormalize,
36	  findPointsInRange,
37	} from "@audio/automation/automation-curve";
38	import { faderTaper } from "@audio/mixer";
39	import { renderMidiClipToAudio } from "./synth-renderer";
40	import { encodeWavHeader, encodePcmChunk, assembleWav } from "./wav-encoder";
41	
42	// ─── Session analysis (exported for testing) ───
43	
44	export type SessionBounds = {
45	  readonly start: number;
46	  readonly end: number;
47	};
48	
49	/** Determine which tracks are audible given mute/solo state */
50	function getAudibleTrackIds(tracks: readonly TrackModel[]): Set<string> {
51	  const hasSolo = tracks.some((t) => t.solo);
52	  const audible = new Set<string>();
53	
54	  for (const track of tracks) {
55	    if (track.muted) continue;
56	    if (hasSolo && !track.solo && !track.soloIsolate) continue;
57	    audible.add(track.id);
58	  }
59	
60	  return audible;
61	}
62	
63	/** Compute the time bounds of all audible clips in the session */
64	export function computeSessionBounds(
65	  tracks: readonly TrackModel[],
66	  clips: Readonly<Record<string, ClipModel>>,
67	): SessionBounds {
68	  const audible = getAudibleTrackIds(tracks);
69	  let start = Infinity;
70	  let end = 0;
71	
72	  for (const track of tracks) {
73	    if (!audible.has(track.id)) continue;
74	    for (const clipId of track.clipIds) {
75	      const clip = clips[clipId];
76	      if (!clip) continue;
77	      start = Math.min(start, clip.startTime);
78	      end = Math.max(end, clip.startTime + clip.duration);
79	    }
80	  }
81	
82	  if (start === Infinity) start = 0;
83	  return { start, end };
84	}
85	
86	// ─── Event timeline (exported for testing) ───
87	
88	export type TimelineAudioClip = {
89	  readonly clip: AudioClipModel;
90	  readonly trackId: string;
91	};
92	
93	export type TimelineMidiClip = {
94	  readonly clip: MidiClipModel;
95	  readonly trackId: string;
96	};
97	
98	export type EventTimeline = {
99	  readonly audioClips: readonly TimelineAudioClip[];
100	  readonly midiClips: readonly TimelineMidiClip[];
101	};
102	
103	/** Build a timeline of events for audible tracks */
104	export function buildEventTimeline(
105	  tracks: readonly TrackModel[],
106	  clips: Readonly<Record<string, ClipModel>>,
107	): EventTimeline {
108	  const audible = getAudibleTrackIds(tracks);
109	  const audioClips: TimelineAudioClip[] = [];
110	  const midiClips: TimelineMidiClip[] = [];
111	
112	  for (const track of tracks) {
113	    if (!audible.has(track.id)) continue;
114	    for (const clipId of track.clipIds) {
115	      const clip = clips[clipId];
116	      if (!clip) continue;
117	      if (isAudioClip(clip)) {
118	        audioClips.push({ clip, trackId: track.id });
119	      } else if (isMidiClip(clip)) {
120	        midiClips.push({ clip, trackId: track.id });
121	      }
122	    }
123	  }
124	
125	  return { audioClips, midiClips };
126	}
127	
128	// ─── Offline mixer graph ───
129	
130	type OfflineMixerStrip = {
131	  inputGain: GainNode;
132	  faderGain: GainNode;
133	  panner: StereoPannerNode;
134	  muteGain: GainNode;
135	};
136	
137	type OfflineMixer = {
138	  strips: Map<string, OfflineMixerStrip>;
139	  masterInput: GainNode;
140	  masterFader: GainNode;
141	  limiter: DynamicsCompressorNode;
142	};
143	
144	function buildOfflineMixer(
145	  ctx: OfflineAudioContext,
146	  tracks: readonly TrackModel[],
147	  masterLevel: number,
148	  audibleIds: Set<string>,
149	): OfflineMixer {
150	  // Master bus
151	  const masterInput = ctx.createGain();
152	  const masterFader = ctx.createGain();
153	  const limiter = ctx.createDynamicsCompressor();
154	
155	  // INV-2: Brickwall limiter
156	  limiter.threshold.value = -1;
157	  limiter.ratio.value = 20;
158	  limiter.knee.value = 0;
159	  limiter.attack.value = 0.001;
160	  limiter.release.value = 0.01;
161	
162	  masterInput.connect(masterFader);
163	  masterFader.connect(limiter);
164	  limiter.connect(ctx.destination);
165	  masterFader.gain.value = masterLevel;
166	
167	  // Channel strips
168	  const strips = new Map<string, OfflineMixerStrip>();
169	  for (const track of tracks) {
170	    if (!audibleIds.has(track.id)) continue;
171	
172	    const inputGain = ctx.createGain();
173	    const faderGain = ctx.createGain();
174	    const panner = ctx.createStereoPanner();
175	    const muteGain = ctx.createGain();
176	
177	    inputGain.connect(faderGain);
178	    faderGain.connect(panner);
179	    panner.connect(muteGain);
180	    muteGain.connect(masterInput);
181	
182	    faderGain.gain.value = faderTaper(track.volume);
183	    panner.pan.value = track.pan;
184	    muteGain.gain.value = 1; // Already filtered by audibleIds
185	
186	    strips.set(track.id, { inputGain, faderGain, panner, muteGain });
187	  }
188	
189	  return { strips, masterInput, masterFader, limiter };
190	}
191	
192	// ─── Audio clip scheduling ───
193	
194	function scheduleAudioClips(
195	  ctx: OfflineAudioContext,
196	  audioClips: readonly TimelineAudioClip[],
197	  mixer: OfflineMixer,
198	  rangeStart: number,
199	  getBuffer: (sourceId: string) => AudioBuffer | undefined,
200	): void {
201	  for (const { clip, trackId } of audioClips) {
202	    const strip = mixer.strips.get(trackId);
203	    if (!strip) continue;
204	
205	    const buffer = getBuffer(clip.sourceId);
206	    if (!buffer) continue;
207	
208	    // Compute timing relative to range start
209	    const clipStart = clip.startTime - rangeStart;
210	    const clipEnd = clipStart + clip.duration;
211	
212	    // Skip if clip is entirely before the render window
213	    if (clipEnd <= 0) continue;
214	
215	    // Handle clips that start before the render window
216	    const seekOffset = clipStart < 0 ? -clipStart : 0;
217	    const sourceOffset = clip.sourceOffset + seekOffset;
218	    const playDuration = clip.duration - seekOffset;
219	    const playStart = Math.max(0, clipStart);
220	
221	    const source = ctx.createBufferSource();
222	    source.buffer = buffer;
223	
224	    const gainNode = ctx.createGain();
225	    gainNode.gain.value = clip.gain;
226	
227	    // Apply fades, accounting for seek offset
228	    const maxFadeIn = Math.min(clip.fadeIn, clip.duration);
229	    const maxFadeOut = Math.min(clip.fadeOut, clip.duration - maxFadeIn);
230	
231	    // Fade-in: skip or shorten if we're seeking past it
232	    if (maxFadeIn > 0 && seekOffset < maxFadeIn) {
233	      const fadeInRemaining = maxFadeIn - seekOffset;
234	      const startGain =
235	        seekOffset > 0 ? (seekOffset / maxFadeIn) * clip.gain : 0;
236	      gainNode.gain.setValueAtTime(startGain, playStart);
237	      gainNode.gain.linearRampToValueAtTime(
238	        clip.gain,
239	        playStart + fadeInRemaining,
240	      );
241	    }
242	
243	    if (maxFadeOut > 0) {
244	      const fadeOutStart = clipEnd - maxFadeOut;
245	      gainNode.gain.setValueAtTime(clip.gain, Math.max(0, fadeOutStart));
246	      gainNode.gain.linearRampToValueAtTime(0, clipEnd);
247	    }
248	
249	    source.connect(gainNode);
250	    gainNode.connect(strip.inputGain);
251	    source.start(playStart, sourceOffset, playDuration);
252	  }
253	}
254	
255	// ─── MIDI pre-rendering ───
256	
257	function scheduleMidiClips(
258	  ctx: OfflineAudioContext,
259	  midiClips: readonly TimelineMidiClip[],
260	  mixer: OfflineMixer,
261	  rangeStart: number,
262	  instruments: ReadonlyMap<string, TrackInstrumentConfig>,
263	): void {
264	  for (const { clip, trackId } of midiClips) {
265	    const strip = mixer.strips.get(trackId);
266	    if (!strip) continue;
267	
268	    const config = instruments.get(trackId);
269	    if (!config || config.type !== "synth") continue;
270	
271	    // Pre-render MIDI to audio using synth DSP
272	    const rendered = renderMidiClipToAudio(
273	      clip.noteEvents,
274	      clip.duration,
275	      ctx.sampleRate,
276	      config.params,
277	    );
278	
279	    // Create AudioBuffer from rendered data
280	    const audioBuffer = ctx.createBuffer(
281	      2,
282	      rendered.left.length,
283	      ctx.sampleRate,
284	    );
285	    audioBuffer.copyToChannel(rendered.left, 0);
286	    audioBuffer.copyToChannel(rendered.right, 1);
287	
288	    // Schedule playback
289	    const clipStart = clip.startTime - rangeStart;
290	    if (clipStart + clip.duration <= 0) continue;
291	
292	    const source = ctx.createBufferSource();
293	    source.buffer = audioBuffer;
294	
295	    const seekOffset = clipStart < 0 ? -clipStart : 0;
296	    const playStart = Math.max(0, clipStart);
297	
298	    source.connect(strip.inputGain);
299	    source.start(playStart, seekOffset, clip.duration - seekOffset);
300	  }
301	}
302	
303	// ─── Drum scheduling ───
304	
305	function scheduleDrumClips(
306	  ctx: OfflineAudioContext,
307	  midiClips: readonly TimelineMidiClip[],
308	  mixer: OfflineMixer,
309	  rangeStart: number,
310	  instruments: ReadonlyMap<string, TrackInstrumentConfig>,
311	): void {
312	  for (const { clip, trackId } of midiClips) {
313	    const strip = mixer.strips.get(trackId);
314	    if (!strip) continue;
315	
316	    const config = instruments.get(trackId);
317	    if (!config || config.type !== "drums") continue;
318	
319	    // Schedule individual drum hits
320	    for (const note of clip.noteEvents) {
321	      const hitTime = clip.startTime + note.startTime - rangeStart;
322	      const drumId = mapPitchToDrum(note.pitch);
323	      if (!drumId) continue;
324	
325	      const sampleBuffer = config.samples.get(drumId);
326	      if (!sampleBuffer) continue;
327	
328	      const drumParams = config.params.get(drumId);
329	      const decay = drumParams?.decay ?? 0.5;
330	
331	      // Skip if the hit + its decay is entirely before the render window
332	      if (hitTime + decay <= 0) continue;
333	
334	      const velocity = note.velocity / 127;
335	      const source = ctx.createBufferSource();
336	      source.buffer = sampleBuffer;
337	
338	      // Handle hits that start before the render window (play tail only)
339	      const seekOffset = hitTime < 0 ? -hitTime : 0;
340	      const playStart = Math.max(0, hitTime);
341	
342	      if (drumParams) {
343	        source.playbackRate.setValueAtTime(drumParams.tune, playStart);
344	      }
345	
346	      const gain = ctx.createGain();
347	      const peakGain = Math.max(0.001, (drumParams?.volume ?? 1) * velocity);
348	      // Compute decayed gain at seek point
349	      const gainAtSeek =
350	        seekOffset > 0
351	          ? peakGain * Math.exp(-seekOffset / (decay * 0.3))
352	          : peakGain;
353	      gain.gain.setValueAtTime(Math.max(0.001, gainAtSeek), playStart);
354	      gain.gain.exponentialRampToValueAtTime(0.001, hitTime + decay);
355	
356	      source.connect(gain);
357	      gain.connect(strip.inputGain);
358	      source.start(playStart, seekOffset);
359	      source.stop(hitTime + decay + 0.01);
360	    }
361	  }
362	}
