1	/**
2	 * WAV file encoder with incremental chunk support.
3	 * Supports 16-bit PCM, 24-bit PCM, and 32-bit IEEE float.
4	 *
5	 * Two modes:
6	 * 1. Single-pass: encodeWav() for small files
7	 * 2. Chunked: encodeWavHeader() + encodePcmChunk()* + assembleWav()
8	 */
9	
10	function clamp(v: number, min: number, max: number): number {
11	  return Math.min(max, Math.max(min, v));
12	}
13	
14	function writeString(view: DataView, offset: number, str: string): void {
15	  for (let i = 0; i < str.length; i++) {
16	    view.setUint8(offset + i, str.charCodeAt(i));
17	  }
18	}
19	
20	/**
21	 * Encode a WAV file header (44 bytes).
22	 * @param numChannels - Number of audio channels (1 = mono, 2 = stereo)
23	 * @param sampleRate - Sample rate in Hz
24	 * @param bitDepth - Bits per sample (16, 24, or 32)
25	 * @param totalSamples - Total number of sample frames (not total samples across all channels)
26	 */
27	export function encodeWavHeader(
28	  numChannels: number,
29	  sampleRate: number,
30	  bitDepth: 16 | 24 | 32,
31	  totalSamples: number,
32	): ArrayBuffer {
33	  const bytesPerSample = bitDepth / 8;
34	  const blockAlign = numChannels * bytesPerSample;
35	  const byteRate = sampleRate * blockAlign;
36	  const dataSize = totalSamples * blockAlign;
37	  const isFloat = bitDepth === 32;
38	  const formatCode = isFloat ? 3 : 1; // 3 = IEEE float, 1 = PCM
39	  // IEEE float requires 18-byte fmt chunk (with cbSize=0); PCM uses 16
40	  const fmtChunkSize = isFloat ? 18 : 16;
41	  const headerSize = 20 + fmtChunkSize + 8; // RIFF(12) + fmt(8+fmtChunkSize) + data(8)
42	
43	  const buffer = new ArrayBuffer(headerSize);
44	  const view = new DataView(buffer);
45	
46	  // RIFF header
47	  writeString(view, 0, "RIFF");
48	  view.setUint32(4, headerSize - 8 + dataSize, true); // file size - 8
49	  writeString(view, 8, "WAVE");
50	
51	  // fmt sub-chunk
52	  writeString(view, 12, "fmt ");
53	  view.setUint32(16, fmtChunkSize, true);
54	  view.setUint16(20, formatCode, true);
55	  view.setUint16(22, numChannels, true);
56	  view.setUint32(24, sampleRate, true);
57	  view.setUint32(28, byteRate, true);
58	  view.setUint16(32, blockAlign, true);
59	  view.setUint16(34, bitDepth, true);
60	
61	  const dataOffset = 20 + fmtChunkSize;
62	  if (isFloat) {
63	    view.setUint16(36, 0, true); // cbSize = 0
64	  }
65	
66	  // data sub-chunk
67	  writeString(view, dataOffset, "data");
68	  view.setUint32(dataOffset + 4, dataSize, true);
69	
70	  return buffer;
71	}
72	
73	/**
74	 * Encode a chunk of interleaved PCM data from channel arrays.
75	 * @param channels - Array of Float32Arrays, one per channel
76	 * @param bitDepth - Bits per sample (16, 24, or 32)
77	 */
78	export function encodePcmChunk(
79	  channels: readonly Float32Array[],
80	  bitDepth: 16 | 24 | 32,
81	): ArrayBuffer {
82	  const numChannels = channels.length;
83	  const firstChannel = channels[0];
84	  if (!firstChannel || numChannels === 0) return new ArrayBuffer(0);
85	
86	  const numSamples = firstChannel.length;
87	  const bytesPerSample = bitDepth / 8;
88	  const buffer = new ArrayBuffer(numSamples * numChannels * bytesPerSample);
89	
90	  if (bitDepth === 16) {
91	    const view = new DataView(buffer);
92	    let offset = 0;
93	    for (let s = 0; s < numSamples; s++) {
94	      for (let c = 0; c < numChannels; c++) {
95	        const ch = channels[c];
96	        const sample = ch ? clamp(ch[s] ?? 0, -1, 1) : 0;
97	        const int16 = Math.round(sample < 0 ? sample * 32768 : sample * 32767);
98	        view.setInt16(offset, int16, true);
99	        offset += 2;
100	      }
101	    }
102	  } else if (bitDepth === 24) {
103	    const bytes = new Uint8Array(buffer);
104	    let offset = 0;
105	    for (let s = 0; s < numSamples; s++) {
106	      for (let c = 0; c < numChannels; c++) {
107	        const ch = channels[c];
108	        const sample = ch ? clamp(ch[s] ?? 0, -1, 1) : 0;
109	        const int24 = Math.round(
110	          sample < 0 ? sample * 8388608 : sample * 8388607,
111	        );
112	        bytes[offset++] = int24 & 0xff;
113	        bytes[offset++] = (int24 >> 8) & 0xff;
114	        bytes[offset++] = (int24 >> 16) & 0xff;
115	      }
116	    }
117	  } else {
118	    // 32-bit float
119	    const view = new DataView(buffer);
120	    let offset = 0;
121	    for (let s = 0; s < numSamples; s++) {
122	      for (let c = 0; c < numChannels; c++) {
123	        const ch = channels[c];
124	        view.setFloat32(offset, ch?.[s] ?? 0, true);
125	        offset += 4;
126	      }
127	    }
128	  }
129	
130	  return buffer;
131	}
132	
133	/**
134	 * Assemble a WAV file from a header and data chunks.
135	 */
136	export function assembleWav(
137	  header: ArrayBuffer,
138	  chunks: readonly ArrayBuffer[],
139	): Blob {
140	  return new Blob([header, ...chunks], { type: "audio/wav" });
141	}
142	
143	/**
144	 * Single-pass WAV encoding: header + all data in one call.
145	 * @param channels - Array of Float32Arrays, one per channel
146	 * @param sampleRate - Sample rate in Hz
147	 * @param bitDepth - Bits per sample (16, 24, or 32)
148	 */
149	export function encodeWav(
150	  channels: readonly Float32Array[],
151	  sampleRate: number,
152	  bitDepth: 16 | 24 | 32,
153	): Blob {
154	  const firstChannel = channels[0];
155	  const numSamples = firstChannel?.length ?? 0;
156	  const header = encodeWavHeader(
157	    channels.length,
158	    sampleRate,
159	    bitDepth,
160	    numSamples,
161	  );
162	  const data = encodePcmChunk(channels, bitDepth);
163	  return assembleWav(header, [data]);
164	}
