1	/**
2	 * Offline synth renderer: renders MIDI note events to stereo audio
3	 * using the synth DSP functions directly (no AudioWorklet dependency).
4	 *
5	 * This mirrors the SynthProcessor logic but runs synchronously,
6	 * producing Float32Arrays suitable for use as AudioBufferSourceNodes
7	 * in the offline bounce context.
8	 */
9	
10	import type { MIDINoteEvent } from "@state/track/types";
11	import type { SynthParameterMap } from "@audio/synth/synth-types";
12	import { midiToFreq } from "@audio/synth/synth-types";
13	import { createPolyBLEPOsc } from "@audio/synth/dsp/polyblep";
14	import { createADSREnvelope, type ADSRParams } from "@audio/synth/dsp/adsr";
15	import {
16	  computeBiquadCoeffs,
17	  createBiquadFilter,
18	} from "@audio/synth/dsp/biquad-coeffs";
19	import { createLFO } from "@audio/synth/dsp/lfo";
20	import {
21	  createModAccumulators,
22	  resetAccumulators,
23	  applyModRoute,
24	  SOURCE_INDEX,
25	  type WorkletModRoute,
26	  type ModAccumulators,
27	} from "@audio/synth/modulation-engine";
28	
29	const MAX_VOICES = 16;
30	
31	type OfflineVoice = {
32	  active: boolean;
33	  releasing: boolean;
34	  note: number;
35	  osc1: ReturnType<typeof createPolyBLEPOsc>;
36	  osc2: ReturnType<typeof createPolyBLEPOsc>;
37	  ampEnv: ReturnType<typeof createADSREnvelope>;
38	  filterEnv: ReturnType<typeof createADSREnvelope>;
39	  filter: ReturnType<typeof createBiquadFilter>;
40	  targetFreq: number;
41	  currentFreq: number;
42	  velocity: number;
43	};
44	
45	function createOfflineVoice(): OfflineVoice {
46	  return {
47	    active: false,
48	    releasing: false,
49	    note: -1,
50	    osc1: createPolyBLEPOsc("saw"),
51	    osc2: createPolyBLEPOsc("saw"),
52	    ampEnv: createADSREnvelope(),
53	    filterEnv: createADSREnvelope(),
54	    filter: createBiquadFilter("lowpass"),
55	    targetFreq: 440,
56	    currentFreq: 440,
57	    velocity: 0,
58	  };
59	}
60	
61	type NoteEvent = {
62	  sample: number;
63	  type: "on" | "off";
64	  note: number;
65	  velocity: number;
66	};
67	
68	export type RenderedAudio = {
69	  readonly left: Float32Array;
70	  readonly right: Float32Array;
71	};
72	
73	/**
74	 * Render MIDI note events to stereo audio using synth DSP.
75	 * @param notes - MIDI note events (startTime relative to clip start)
76	 * @param duration - Total duration to render in seconds
77	 * @param sampleRate - Sample rate
78	 * @param params - Synth parameter snapshot
79	 * @param modRoutes - Optional modulation routes (mirrors SynthProcessor mod matrix)
80	 */
81	export function renderMidiClipToAudio(
82	  notes: readonly MIDINoteEvent[],
83	  duration: number,
84	  sampleRate: number,
85	  params: SynthParameterMap,
86	  modRoutes: readonly WorkletModRoute[] = [],
87	): RenderedAudio {
88	  const totalSamples = Math.ceil(duration * sampleRate);
89	  const left = new Float32Array(totalSamples);
90	  const right = new Float32Array(totalSamples);
91	
92	  if (notes.length === 0) return { left, right };
93	
94	  // Build sorted event list (note-ons and note-offs)
95	  const events: NoteEvent[] = [];
96	  for (const note of notes) {
97	    const onSample = Math.floor(note.startTime * sampleRate);
98	    const offSample = Math.floor((note.startTime + note.duration) * sampleRate);
99	    events.push({
100	      sample: onSample,
101	      type: "on",
102	      note: note.pitch,
103	      velocity: note.velocity,
104	    });
105	    events.push({
106	      sample: offSample,
107	      type: "off",
108	      note: note.pitch,
109	      velocity: 0,
110	    });
111	  }
112	  events.sort((a, b) => a.sample - b.sample || (a.type === "off" ? -1 : 1));
113	
114	  // Pre-allocate voices
115	  const voices: OfflineVoice[] = Array.from({ length: MAX_VOICES }, () =>
116	    createOfflineVoice(),
117	  );
118	
119	  // LFOs for modulation (mirrors SynthProcessor)
120	  const lfo1 = createLFO(params.lfo1Shape);
121	  const lfo2 = createLFO(params.lfo2Shape);
122	  const modSourceValues = new Float64Array(8);
123	  const modAccGlobal: ModAccumulators = createModAccumulators();
124	  const modAccVoice: ModAccumulators = createModAccumulators();
125	  const voiceSrcValues = new Float64Array(8);
126	
127	  // ADSR params (pre-allocated)
128	  const ampParams: ADSRParams = {
129	    attack: params.ampAttack,
130	    decay: params.ampDecay,
131	    sustain: params.ampSustain,
132	    release: params.ampRelease,
133	  };
134	  const filterParams: ADSRParams = {
135	    attack: params.filterAttack,
136	    decay: params.filterDecay,
137	    sustain: params.filterSustain,
138	    release: params.filterRelease,
139	  };
140	
141	  // Pre-compute constants
142	  const osc1OctMul = Math.pow(2, params.osc1Octave);
143	  const osc1DetMul = Math.pow(2, params.osc1Detune / 1200);
144	  const osc2OctMul = Math.pow(2, params.osc2Octave);
145	  const osc2DetMul = Math.pow(2, params.osc2Detune / 1200);
146	
147	  let eventIdx = 0;
148	
149	  for (let s = 0; s < totalSamples; s++) {
150	    // Process events at this sample
151	    while (eventIdx < events.length) {
152	      const evt = events[eventIdx];
153	      if (!evt || evt.sample > s) break;
154	
155	      if (evt.type === "on") {
156	        allocateNoteOn(voices, evt.note, evt.velocity, params, sampleRate);
157	      } else {
158	        releaseNote(voices, evt.note);
159	      }
160	      eventIdx++;
161	    }
162	
163	    // LFO processing (global, before voice loop — mirrors SynthProcessor)
164	    const lfo1Rate = Math.max(0.01, params.lfo1Rate + modAccGlobal.lfo1Rate);
165	    const lfo2Rate = Math.max(0.01, params.lfo2Rate + modAccGlobal.lfo2Rate);
166	    const lfo1Val = lfo1.process(lfo1Rate, sampleRate);
167	    const lfo2Val = lfo2.process(lfo2Rate, sampleRate);
168	
169	    modSourceValues[SOURCE_INDEX.lfo1] = lfo1Val * params.lfo1Depth;
170	    modSourceValues[SOURCE_INDEX.lfo2] = lfo2Val * params.lfo2Depth;
171	
172	    // Compute global modulation accumulation
173	    resetAccumulators(modAccGlobal);
174	    for (const route of modRoutes) {
175	      const si = route.sourceIdx;
176	      if (
177	        si === SOURCE_INDEX.lfo1 ||
178	        si === SOURCE_INDEX.lfo2 ||
179	        si === SOURCE_INDEX.aftertouch ||
180	        si === SOURCE_INDEX.modWheel ||
181	        si === SOURCE_INDEX.pitchBend
182	      ) {
183	        applyModRoute(
184	          modAccGlobal,
185	          modSourceValues,
186	          si,
187	          route.destIdx,
188	          route.amount,
189	          route.bipolar,
190	        );
191	      }
192	    }
193	
194	    let mixL = 0;
195	    let mixR = 0;
196	
197	    for (let vi = 0; vi < MAX_VOICES; vi++) {
198	      const v = voices[vi];
199	      if (!v || !v.active) continue;
200	
201	      // Check if release finished
202	      if (v.ampEnv.stage === "idle" && v.releasing) {
203	        v.active = false;
204	        v.releasing = false;
205	        continue;
206	      }
207	
208	      // Pitch glide
209	      if (params.glideTime > 0 && v.currentFreq !== v.targetFreq) {
210	        const glideCoeff = 1 - Math.exp(-1 / (params.glideTime * sampleRate));
211	        v.currentFreq += glideCoeff * (v.targetFreq - v.currentFreq);
212	      } else {
213	        v.currentFreq = v.targetFreq;
214	      }
215	
216	      const baseFreq = v.currentFreq;
217	
218	      // Envelopes
219	      const filterEnvVal = v.filterEnv.process(filterParams, sampleRate);
220	      const ampLevel = v.ampEnv.process(ampParams, sampleRate);
221	
222	      // Per-voice modulation
223	      resetAccumulators(modAccVoice);
224	      if (modRoutes.length > 0) {
225	        voiceSrcValues[SOURCE_INDEX.ampEnv] = ampLevel;
226	        voiceSrcValues[SOURCE_INDEX.filterEnv] = filterEnvVal;
227	        voiceSrcValues[SOURCE_INDEX.velocity] = v.velocity;
228	
229	        for (const route of modRoutes) {
230	          const si = route.sourceIdx;
231	          if (
232	            si === SOURCE_INDEX.ampEnv ||
233	            si === SOURCE_INDEX.filterEnv ||
234	            si === SOURCE_INDEX.velocity
235	          ) {
236	            applyModRoute(
237	              modAccVoice,
238	              voiceSrcValues,
239	              si,
240	              route.destIdx,
241	              route.amount,
242	              route.bipolar,
243	            );
244	          }
245	        }
246	      }
247	
248	      // Combined modulation (global + per-voice)
249	      const modPitchOsc1 = modAccGlobal.osc1Pitch + modAccVoice.osc1Pitch;
250	      const modPitchOsc2 = modAccGlobal.osc2Pitch + modAccVoice.osc2Pitch;
251	      const modFilterCutoff =
252	        modAccGlobal.filterCutoff + modAccVoice.filterCutoff;
253	      const modFilterReso =
254	        modAccGlobal.filterResonance + modAccVoice.filterResonance;
255	      const modAmpLevel = modAccGlobal.ampLevel + modAccVoice.ampLevel;
256	      const modOscMix = modAccGlobal.oscMix + modAccVoice.oscMix;
257	
258	      // Pitch modulation (scaled to semitones, max +/-24)
259	      const pitchMult1 = Math.pow(2, (modPitchOsc1 * 24) / 12);
260	      const pitchMult2 = Math.pow(2, (modPitchOsc2 * 24) / 12);
261	
262	      // Oscillators
263	      const freq1 = baseFreq * osc1OctMul * osc1DetMul * pitchMult1;
264	      const freq2 = baseFreq * osc2OctMul * osc2DetMul * pitchMult2;
265	      const osc1Out = v.osc1.next(freq1, sampleRate) * params.osc1Level;
266	      const osc2Out = v.osc2.next(freq2, sampleRate) * params.osc2Level;
267	
268	      // Osc mix modulation
269	      const osc1Gain = Math.max(0, Math.min(1, 1 - modOscMix));
270	      const osc2Gain = Math.max(0, Math.min(1, 1 + modOscMix));
271	      let sample = osc1Out * osc1Gain + osc2Out * osc2Gain;
272	
273	      // Filter (recompute coefficients periodically for efficiency)
274	      if (s % 128 === 0) {
275	        const cutoffModSt =
276	          filterEnvVal * params.filterEnvDepth + modFilterCutoff * 60;
277	        const modulatedCutoff =
278	          params.filterCutoff * Math.pow(2, cutoffModSt / 12);
279	        const clampedCutoff = Math.min(
280	          Math.max(modulatedCutoff, 20),
281	          sampleRate / 2 - 100,
282	        );
283	        const modulatedReso = Math.max(
284	          0.5,
285	          Math.min(20, params.filterResonance + modFilterReso * 10),
286	        );
287	        computeBiquadCoeffs(
288	          params.filterType,
289	          clampedCutoff,
290	          modulatedReso,
291	          sampleRate,
292	          v.filter.coeffs,
293	        );
294	      }
295	
296	      sample = v.filter.process(sample);
297	
298	      // Amplitude modulation: base envelope * (1 + mod offset)
299	      const ampMod = Math.max(0, 1 + modAmpLevel);
300	
301	      // Velocity -> amplitude
302	      const velAmp = 0.5 + v.velocity * 0.5;
303	      sample *= ampLevel * ampMod * velAmp * params.masterGain;
304	
305	      // Clamp to prevent overflow
306	      if (!isFinite(sample)) sample = 0;
307	
308	      mixL += sample;
309	      mixR += sample;
310	    }
311	
312	    left[s] = mixL;
313	    right[s] = mixR;
314	  }
315	
316	  return { left, right };
317	}
318	
319	/** Allocate a voice for a new note (oldest-steal if full) */
320	function allocateNoteOn(
321	  voices: OfflineVoice[],
322	  note: number,
323	  velocity: number,
324	  params: SynthParameterMap,
325	  sampleRate: number,
326	): void {
327	  // Find free voice
328	  let idx = -1;
329	  for (let i = 0; i < MAX_VOICES; i++) {
330	    if (voices[i]?.active !== true) {
331	      idx = i;
332	      break;
333	    }
334	  }
335	
336	  // Steal oldest releasing voice if no free voice
337	  if (idx === -1) {
338	    for (let i = 0; i < MAX_VOICES; i++) {
339	      if (voices[i]?.releasing === true) {
340	        idx = i;
341	        break;
342	      }
343	    }
344	  }
345	
346	  // Steal first voice as last resort
347	  if (idx === -1) idx = 0;
348	
349	  const v = voices[idx];
350	  if (!v) return;
351	
352	  const freq = midiToFreq(note);
353	  v.active = true;
354	  v.releasing = false;
355	  v.note = note;
356	  v.velocity = velocity / 127;
357	  v.targetFreq = freq;
358	  v.currentFreq = freq;
359	
360	  v.osc1.reset();
361	  v.osc2.reset();
362	  v.filter.reset();
363	  v.osc1.type = params.osc1Type;
364	  v.osc2.type = params.osc2Type;
365	  v.filter.type = params.filterType;
366	
367	  // Compute initial biquad coefficients so the filter doesn't produce silence
368	  // until the next s % 128 boundary in the render loop.
369	  computeBiquadCoeffs(
370	    params.filterType,
371	    Math.min(Math.max(params.filterCutoff, 20), sampleRate / 2 - 100),
372	    params.filterResonance,
373	    sampleRate,
374	    v.filter.coeffs,
375	  );
376	
377	  v.ampEnv.gate(false);
378	  v.filterEnv.gate(false);
379	}
380	
381	/** Release all voices playing this note */
382	function releaseNote(voices: OfflineVoice[], note: number): void {
383	  for (let i = 0; i < MAX_VOICES; i++) {
384	    const v = voices[i];
385	    if (v && v.active && !v.releasing && v.note === note) {
386	      v.releasing = true;
387	      v.ampEnv.release();
388	      v.filterEnv.release();
389	    }
390	  }
391	}
