1	/**
2	 * Zustand store for per-track automation lanes.
3	 * Follows effects-store.ts pattern: keyed by track ID.
4	 */
5	
6	import { create } from "zustand";
7	import type {
8	  AutomationLane,
9	  AutomationMode,
10	  AutomationPoint,
11	  ParameterTarget,
12	} from "@audio/automation";
13	import {
14	  insertPoint as insertPt,
15	  removePoint as removePt,
16	  movePoint as movePt,
17	  targetsEqual,
18	} from "@audio/automation";
19	import { nextLaneId } from "@audio/automation/automation-types";
20	
21	export type AutomationStore = {
22	  /** Per-track automation lanes keyed by track ID */
23	  lanes: Record<string, readonly AutomationLane[]>;
24	
25	  addLane: (trackId: string, target: ParameterTarget) => void;
26	  removeLane: (trackId: string, laneId: string) => void;
27	  removeTrackLanes: (trackId: string) => void;
28	  addPoint: (trackId: string, laneId: string, point: AutomationPoint) => void;
29	  removePoint: (trackId: string, laneId: string, pointId: string) => void;
30	  movePoint: (
31	    trackId: string,
32	    laneId: string,
33	    pointId: string,
34	    newTime: number,
35	    newValue: number,
36	  ) => void;
37	  setMode: (trackId: string, laneId: string, mode: AutomationMode) => void;
38	  setArmed: (trackId: string, laneId: string, armed: boolean) => void;
39	  getLanes: (trackId: string) => readonly AutomationLane[];
40	  getLane: (trackId: string, laneId: string) => AutomationLane | undefined;
41	};
42	
43	function updateLane(
44	  lanes: readonly AutomationLane[],
45	  laneId: string,
46	  updater: (lane: AutomationLane) => AutomationLane,
47	): readonly AutomationLane[] {
48	  return lanes.map((l) => (l.id === laneId ? updater(l) : l));
49	}
50	
51	export const useAutomationStore = create<AutomationStore>()((set, get) => ({
52	  lanes: {},
53	
54	  addLane(trackId, target) {
55	    set((s) => {
56	      const existing = s.lanes[trackId] ?? [];
57	      // Reject duplicate: one lane per target per track
58	      if (existing.some((l) => targetsEqual(l.target, target))) return s;
59	      const lane: AutomationLane = {
60	        id: nextLaneId(),
61	        trackId,
62	        target,
63	        points: [],
64	        mode: "read",
65	        armed: true,
66	      };
67	      return {
68	        lanes: { ...s.lanes, [trackId]: [...existing, lane] },
69	      };
70	    });
71	  },
72	
73	  removeLane(trackId, laneId) {
74	    set((s) => {
75	      const existing = s.lanes[trackId];
76	      if (!existing) return s;
77	      const next = existing.filter((l) => l.id !== laneId);
78	      if (next.length === 0) {
79	        return {
80	          lanes: Object.fromEntries(
81	            Object.entries(s.lanes).filter(([k]) => k !== trackId),
82	          ),
83	        };
84	      }
85	      return { lanes: { ...s.lanes, [trackId]: next } };
86	    });
87	  },
88	
89	  removeTrackLanes(trackId) {
90	    set((s) => {
91	      if (!s.lanes[trackId]) return s;
92	      return {
93	        lanes: Object.fromEntries(
94	          Object.entries(s.lanes).filter(([k]) => k !== trackId),
95	        ),
96	      };
97	    });
98	  },
99	
100	  addPoint(trackId, laneId, point) {
101	    set((s) => {
102	      const existing = s.lanes[trackId];
103	      if (!existing) return s;
104	      return {
105	        lanes: {
106	          ...s.lanes,
107	          [trackId]: updateLane(existing, laneId, (l) => ({
108	            ...l,
109	            points: insertPt(l.points, point),
110	          })),
111	        },
112	      };
113	    });
114	  },
115	
116	  removePoint(trackId, laneId, pointId) {
117	    set((s) => {
118	      const existing = s.lanes[trackId];
119	      if (!existing) return s;
120	      return {
121	        lanes: {
122	          ...s.lanes,
123	          [trackId]: updateLane(existing, laneId, (l) => ({
124	            ...l,
125	            points: removePt(l.points, pointId),
126	          })),
127	        },
128	      };
129	    });
130	  },
131	
132	  movePoint(trackId, laneId, pointId, newTime, newValue) {
133	    set((s) => {
134	      const existing = s.lanes[trackId];
135	      if (!existing) return s;
136	      return {
137	        lanes: {
138	          ...s.lanes,
139	          [trackId]: updateLane(existing, laneId, (l) => ({
140	            ...l,
141	            points: movePt(l.points, pointId, newTime, newValue),
142	          })),
143	        },
144	      };
145	    });
146	  },
147	
148	  setMode(trackId, laneId, mode) {
149	    set((s) => {
150	      const existing = s.lanes[trackId];
151	      if (!existing) return s;
152	      return {
153	        lanes: {
154	          ...s.lanes,
155	          [trackId]: updateLane(existing, laneId, (l) => ({
156	            ...l,
157	            mode,
158	          })),
159	        },
160	      };
161	    });
162	  },
163	
164	  setArmed(trackId, laneId, armed) {
165	    set((s) => {
166	      const existing = s.lanes[trackId];
167	      if (!existing) return s;
168	      return {
169	        lanes: {
170	          ...s.lanes,
171	          [trackId]: updateLane(existing, laneId, (l) => ({
172	            ...l,
173	            armed,
174	          })),
175	        },
176	      };
177	    });
178	  },
179	
180	  getLanes(trackId) {
181	    return get().lanes[trackId] ?? [];
182	  },
183	
184	  getLane(trackId, laneId) {
185	    const lanes = get().lanes[trackId];
186	    if (!lanes) return undefined;
187	    return lanes.find((l) => l.id === laneId);
188	  },
189	}));
