1	/**
2	 * Pure canvas renderer for the arrangement view.
3	 * No DOM access -- only draws to the CanvasRenderingContext2D passed in.
4	 */
5	import type { TrackModel, ClipModel } from "@state/track/types";
6	import { RULER_HEIGHT, CLIP_PADDING } from "./constants";
7	
8	// -- Design token constants (canvas cannot read CSS vars) ---------------------
9	
10	const COLOR = {
11	  black: "#000000",
12	  white: "#ffffff",
13	  red: "#ff0000",
14	  pink: "#ff2d6f",
15	  gray900: "#111111",
16	  gray700: "#333333",
17	  gray500: "#666666",
18	} as const;
19	
20	const FONT_MONO = "'JetBrains Mono', monospace" as const;
21	const TEXT_XS = 10;
22	const TEXT_SM = 12;
23	const BORDER_WIDTH = 2;
24	const COLOR_STRIP_WIDTH = 4;
25	
26	// -- Public types -------------------------------------------------------------
27	
28	export type ArrangementViewState = {
29	  scrollX: number;
30	  scrollY: number;
31	  pixelsPerSecond: number;
32	  trackHeight: number;
33	  headerWidth: number;
34	};
35	
36	export type RenderContext = {
37	  ctx: CanvasRenderingContext2D;
38	  width: number;
39	  height: number;
40	  view: ArrangementViewState;
41	  tracks: readonly TrackModel[];
42	  clips: Record<string, ClipModel>;
43	  selectedClipIds: readonly string[];
44	  cursorSeconds: number;
45	  bpm: number;
46	};
47	
48	// -- Helpers ------------------------------------------------------------------
49	
50	function secondsToX(seconds: number, view: ArrangementViewState): number {
51	  return view.headerWidth + (seconds - view.scrollX) * view.pixelsPerSecond;
52	}
53	
54	function trackY(index: number, view: ArrangementViewState): number {
55	  return RULER_HEIGHT + index * view.trackHeight - view.scrollY;
56	}
57	
58	/** Convert a hex color (#rrggbb) to rgba with given alpha (0-1). */
59	function hexToRgba(hex: string, alpha: number): string {
60	  if (!/^#[0-9a-fA-F]{6}$/.test(hex)) {
61	    return `rgba(128,128,128,${String(alpha)})`;
62	  }
63	  const r = parseInt(hex.slice(1, 3), 16);
64	  const g = parseInt(hex.slice(3, 5), 16);
65	  const b = parseInt(hex.slice(5, 7), 16);
66	  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
67	}
68	
69	// -- Rendering stages ---------------------------------------------------------
70	
71	function drawBackground(rc: RenderContext): void {
72	  const { ctx, width, height } = rc;
73	  ctx.fillStyle = COLOR.gray900;
74	  ctx.fillRect(0, 0, width, height);
75	}
76	
77	function drawTimeRuler(rc: RenderContext): void {
78	  const { ctx, width, view, bpm } = rc;
79	  const secPerBeat = 60 / bpm;
80	  const secPerBar = secPerBeat * 4;
81	
82	  // Ruler background
83	  ctx.fillStyle = COLOR.black;
84	  ctx.fillRect(0, 0, width, RULER_HEIGHT);
85	
86	  // Bar labels
87	  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
88	  ctx.fillStyle = COLOR.gray500;
89	  ctx.textBaseline = "middle";
90	  ctx.textAlign = "center";
91	
92	  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
93	  const endSec =
94	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
95	  const endBar = Math.ceil(endSec / secPerBar) + 1;
96	
97	  for (let bar = startBar; bar < endBar; bar++) {
98	    const x = secondsToX(bar * secPerBar, view);
99	    if (x >= view.headerWidth && x <= width) {
100	      ctx.fillText(String(bar + 1), x, RULER_HEIGHT / 2);
101	    }
102	  }
103	}
104	
105	function drawGrid(rc: RenderContext): void {
106	  const { ctx, width, height, view, bpm } = rc;
107	  const secPerBeat = 60 / bpm;
108	  const secPerBar = secPerBeat * 4;
109	
110	  // Determine visible range in seconds
111	  const startSec = view.scrollX;
112	  const endSec =
113	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
114	
115	  // Determine grid step -- skip beats when zoomed out too far
116	  const minPxPerLine = 12;
117	  let step = secPerBeat;
118	  while (step * view.pixelsPerSecond < minPxPerLine) {
119	    step *= 2;
120	  }
121	
122	  const firstBeat = Math.floor(startSec / step) * step;
123	
124	  ctx.save();
125	  for (let t = firstBeat; t <= endSec; t += step) {
126	    const x = secondsToX(t, view);
127	    if (x < view.headerWidth || x > width) continue;
128	
129	    // Check if this line sits on a bar boundary (use integer arithmetic to avoid float drift)
130	    const nearestBar = Math.round(t / secPerBar) * secPerBar;
131	    const isBar = Math.abs(t - nearestBar) < 0.001;
132	    ctx.strokeStyle = COLOR.gray700;
133	    ctx.lineWidth = isBar ? 2 : 1;
134	
135	    ctx.beginPath();
136	    ctx.moveTo(x, RULER_HEIGHT);
137	    ctx.lineTo(x, height);
138	    ctx.stroke();
139	  }
140	  ctx.restore();
141	}
142	
143	function drawTrackLanes(rc: RenderContext): void {
144	  const { ctx, width, view, tracks } = rc;
145	
146	  for (let i = 0; i < tracks.length; i++) {
147	    const y = trackY(i, view);
148	    const bottom = y + view.trackHeight;
149	
150	    if (bottom < RULER_HEIGHT || y > rc.height) continue;
151	
152	    // Lane separator
153	    ctx.strokeStyle = COLOR.gray700;
154	    ctx.lineWidth = BORDER_WIDTH;
155	    ctx.beginPath();
156	    ctx.moveTo(0, bottom);
157	    ctx.lineTo(width, bottom);
158	    ctx.stroke();
159	  }
160	}
161	
162	function drawTrackHeaders(rc: RenderContext): void {
163	  const { ctx, view, tracks } = rc;
164	
165	  for (let i = 0; i < tracks.length; i++) {
166	    const track = tracks[i];
167	    if (track === undefined) continue;
168	    const y = trackY(i, view);
169	
170	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
171	
172	    // Header background
173	    ctx.fillStyle = COLOR.black;
174	    ctx.fillRect(0, y, view.headerWidth, view.trackHeight);
175	
176	    // Color strip (4px vertical bar)
177	    ctx.fillStyle = track.color;
178	    ctx.fillRect(0, y, COLOR_STRIP_WIDTH, view.trackHeight);
179	
180	    // Track name
181	    ctx.font = `${String(TEXT_SM)}px ${FONT_MONO}`;
182	    ctx.fillStyle = COLOR.white;
183	    ctx.textBaseline = "middle";
184	    ctx.textAlign = "left";
185	    ctx.fillText(track.name, COLOR_STRIP_WIDTH + 8, y + view.trackHeight / 2);
186	
187	    // Armed indicator (hot pink per R-STA-02)
188	    if (track.armed) {
189	      ctx.fillStyle = COLOR.pink;
190	      ctx.fillRect(0, y, COLOR_STRIP_WIDTH, view.trackHeight);
191	    }
192	
193	    // Mute/Solo indicators
194	    const indicatorY = y + view.trackHeight / 2;
195	    ctx.font = `bold ${String(TEXT_XS)}px ${FONT_MONO}`;
196	    ctx.textAlign = "center";
197	
198	    if (track.armed) {
199	      ctx.fillStyle = COLOR.pink;
200	      ctx.fillText("R", view.headerWidth - 54, indicatorY);
201	    }
202	    if (track.muted) {
203	      ctx.fillStyle = COLOR.gray500;
204	      ctx.fillText("M", view.headerWidth - 36, indicatorY);
205	    }
206	    if (track.solo) {
207	      ctx.fillStyle = COLOR.gray500;
208	      ctx.fillText("S", view.headerWidth - 18, indicatorY);
209	    }
210	
211	    // Header right border
212	    ctx.strokeStyle = COLOR.gray700;
213	    ctx.lineWidth = BORDER_WIDTH;
214	    ctx.beginPath();
215	    ctx.moveTo(view.headerWidth, y);
216	    ctx.lineTo(view.headerWidth, y + view.trackHeight);
217	    ctx.stroke();
218	  }
219	}
220	
221	function drawClips(rc: RenderContext): void {
222	  const { ctx, view, tracks, clips, selectedClipIds } = rc;
223	  const selectedSet = new Set(selectedClipIds);
224	
225	  for (let i = 0; i < tracks.length; i++) {
226	    const track = tracks[i];
227	    if (track === undefined) continue;
228	    const y = trackY(i, view);
229	
230	    if (y + view.trackHeight < RULER_HEIGHT || y > rc.height) continue;
231	
232	    for (const clipId of track.clipIds) {
233	      const clip = clips[clipId];
234	      if (clip === undefined) continue;
235	
236	      const x = secondsToX(clip.startTime, view);
237	      const w = clip.duration * view.pixelsPerSecond;
238	
239	      // Skip clips that are fully out of view
240	      if (x + w < view.headerWidth || x > rc.width) continue;
241	
242	      const clipY = y + CLIP_PADDING;
243	      const clipH = view.trackHeight - CLIP_PADDING * 2;
244	
245	      // Clip fill (track color at 60% opacity)
246	      ctx.fillStyle = hexToRgba(track.color, 0.6);
247	      ctx.fillRect(x, clipY, w, clipH);
248	
249	      // Clip border
250	      const isSelected = selectedSet.has(clip.id);
251	      ctx.strokeStyle = isSelected ? COLOR.white : track.color;
252	      ctx.lineWidth = BORDER_WIDTH;
253	      ctx.strokeRect(x, clipY, w, clipH);
254	
255	      // Clip name label
256	      ctx.save();
257	      ctx.beginPath();
258	      ctx.rect(x, clipY, w, clipH);
259	      ctx.clip();
260	      ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
261	      ctx.fillStyle = COLOR.white;
262	      ctx.textBaseline = "top";
263	      ctx.textAlign = "left";
264	      ctx.fillText(clip.name, x + 4, clipY + 4);
265	      ctx.restore();
266	    }
267	  }
268	}
269	
270	function drawPlayhead(rc: RenderContext): void {
271	  const { ctx, height, view, cursorSeconds } = rc;
272	  const x = secondsToX(cursorSeconds, view);
273	
274	  if (x < view.headerWidth || x > rc.width) return;
275	
276	  ctx.strokeStyle = COLOR.red;
277	  ctx.lineWidth = 2;
278	  ctx.beginPath();
279	  ctx.moveTo(x, 0);
280	  ctx.lineTo(x, height);
281	  ctx.stroke();
282	}
283	
284	// -- Public API ---------------------------------------------------------------
285	
286	export function renderArrangement(rc: RenderContext): void {
287	  drawBackground(rc);
288	  drawTimeRuler(rc);
289	  drawGrid(rc);
290	  drawTrackLanes(rc);
291	  drawTrackHeaders(rc);
292	  drawClips(rc);
293	  drawPlayhead(rc);
294	}
