39	    view,
40	    gridSnap,
41	    onOpenPianoRoll,
42	  );
43	  const bpmForDrop = useDawStore((s) => s.bpm);
44	
45	  const handleDragOver = useCallback(
46	    (e: React.DragEvent<HTMLCanvasElement>): void => {
47	      if (!e.dataTransfer.types.includes("application/x-media-pool-source"))
48	        return;
49	
50	      const rect = e.currentTarget.getBoundingClientRect();
51	      const y = e.clientY - rect.top;
52	      const trackIndex = Math.floor(
53	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
54	      );
55	      const state = useDawStore.getState();
56	      const track = trackIndex >= 0 ? state.tracks[trackIndex] : undefined;
57	      if (track !== undefined && track.type === "audio") {
58	        e.preventDefault();
59	        e.dataTransfer.dropEffect = "copy";
60	      }
61	    },
62	    [view],
63	  );
64	
65	  const handleDrop = useCallback(
66	    (e: React.DragEvent<HTMLCanvasElement>): void => {
67	      const raw = e.dataTransfer.getData("application/x-media-pool-source");
68	      if (!raw) return;
69	      e.preventDefault();
70	
71	      let parsed: unknown;
72	      try {
73	        parsed = JSON.parse(raw);
74	      } catch {
75	        return;
76	      }
77	      const data = parsed as Record<string, unknown>;
78	      if (
79	        typeof data.sourceId !== "string" ||
80	        typeof data.name !== "string" ||
81	        typeof data.durationSeconds !== "number"
82	      )
83	        return;
84	
85	      const rect = e.currentTarget.getBoundingClientRect();
86	      const x = e.clientX - rect.left;
87	      const y = e.clientY - rect.top;
88	
89	      const state = useDawStore.getState();
90	      const trackIndex = Math.floor(
91	        (y - RULER_HEIGHT + view.scrollY) / view.trackHeight,
92	      );
93	      if (trackIndex < 0) return;
94	      const track = state.tracks[trackIndex];
95	      if (track === undefined || track.type !== "audio") return;
96	
97	      const dropTime = snapToGrid(
98	        Math.max(0, xToSeconds(x, view)),
99	        bpmForDrop,
100	        gridSnap,
101	      );
102	
103	      const clip: AudioClipModel = {
104	        type: "audio",
105	        id: "clip-" + crypto.randomUUID(),
106	        trackId: track.id,
107	        sourceId: data.sourceId,
108	        startTime: dropTime,
109	        sourceOffset: 0,
110	        duration: data.durationSeconds,
111	        gain: 1,
112	        fadeIn: 0,
113	        fadeOut: 0,
114	        name: data.name,
115	      };
116	
117	      const cmd = new AddClipCommand(clip);
118	      cmd.execute();
119	      sharedUndoManager.push(cmd);
120	    },
121	    [view, gridSnap, bpmForDrop],
122	  );
123	
124	  const tracks = useDawStore((s) => s.tracks);
125	  const clips = useDawStore((s) => s.clips);
126	  const selectedClipIds = useDawStore((s) => s.selectedClipIds);
127	  const cursorSeconds = useDawStore((s) => s.cursorSeconds);
128	  const bpm = useDawStore((s) => s.bpm);
129	  const transportState = useDawStore((s) => s.transportState);
130	
131	  // Render loop
132	  const render = useCallback((): void => {
133	    const canvas = canvasRef.current;
134	    if (canvas === null) return;
135	    const ctx = canvas.getContext("2d");
136	    if (ctx === null) return;
137	
138	    const rect = canvas.getBoundingClientRect();
139	    renderArrangement({
140	      ctx,
141	      width: rect.width,
142	      height: rect.height,
143	      view,
144	      tracks,
145	      clips,
146	      selectedClipIds,
147	      cursorSeconds,
148	      bpm,
149	    });
150	  }, [view, tracks, clips, selectedClipIds, cursorSeconds, bpm]);

