62	  }
63	  const r = parseInt(hex.slice(1, 3), 16);
64	  const g = parseInt(hex.slice(3, 5), 16);
65	  const b = parseInt(hex.slice(5, 7), 16);
66	  return `rgba(${String(r)},${String(g)},${String(b)},${String(alpha)})`;
67	}
68	
69	// -- Rendering stages ---------------------------------------------------------
70	
71	function drawBackground(rc: RenderContext): void {
72	  const { ctx, width, height } = rc;
73	  ctx.fillStyle = COLOR.gray900;
74	  ctx.fillRect(0, 0, width, height);
75	}
76	
77	function drawTimeRuler(rc: RenderContext): void {
78	  const { ctx, width, view, bpm } = rc;
79	  const secPerBeat = 60 / bpm;
80	  const secPerBar = secPerBeat * 4;
81	
82	  // Ruler background
83	  ctx.fillStyle = COLOR.black;
84	  ctx.fillRect(0, 0, width, RULER_HEIGHT);
85	
86	  // Bar labels
87	  ctx.font = `${String(TEXT_XS)}px ${FONT_MONO}`;
88	  ctx.fillStyle = COLOR.gray500;
89	  ctx.textBaseline = "middle";
90	  ctx.textAlign = "center";
91	
92	  const startBar = Math.max(0, Math.floor(view.scrollX / secPerBar));
93	  const endSec =
94	    view.scrollX + (width - view.headerWidth) / view.pixelsPerSecond;
95	  const endBar = Math.ceil(endSec / secPerBar) + 1;
96	
97	  for (let bar = startBar; bar < endBar; bar++) {
98	    const x = secondsToX(bar * secPerBar, view);
99	    if (x >= view.headerWidth && x <= width) {
100	      ctx.fillText(String(bar + 1), x, RULER_HEIGHT / 2);
101	    }
102	  }
103	}
