153	    ctx.strokeStyle = COLOR.gray700;
154	    ctx.lineWidth = BORDER_WIDTH;
155	    ctx.beginPath();
156	    ctx.moveTo(0, bottom);
157	    ctx.lineTo(width, bottom);
158	    ctx.stroke();
159	  }
160	}
161	
162	function drawTrackHeaders(rc: RenderContext): void {
163	  const { ctx, view, tracks } = rc;
164	
165	  for (let i = 0; i < tracks.length; i++) {
166	    const track = tracks[i];
167	    if (track === undefined) continue;
