191	    }
192	
193	    // Mute/Solo indicators
194	    const indicatorY = y + view.trackHeight / 2;
195	    ctx.font = `bold ${String(TEXT_XS)}px ${FONT_MONO}`;
196	    ctx.textAlign = "center";
197	
198	    if (track.armed) {
199	      ctx.fillStyle = COLOR.pink;
200	      ctx.fillText("R", view.headerWidth - 54, indicatorY);
201	    }
202	    if (track.muted) {
203	      ctx.fillStyle = COLOR.gray500;
204	      ctx.fillText("M", view.headerWidth - 36, indicatorY);
205	    }
206	    if (track.solo) {
