  border: var(--border-width) solid var(--color-black);
  border-radius: 0;
  background: var(--color-gray-900);
  color: var(--color-white);
  font-family: var(--font-mono);
  padding: 0;
  min-width: 320px;
  max-width: 90vw;
  animation: dialogIn var(--transition-normal) ease-out;
}

.dialog::backdrop {
  background: rgba(0, 0, 0, 0.85);
  animation: backdropIn var(--transition-normal) ease-out;
}

@keyframes dialogIn {
  from {
    opacity: 0;
    transform: scale(0.97);
  }
  to {
    opacity: 1;
    transform: scale(1);
  }
}

@keyframes backdropIn {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

.titleBar {
  padding: var(--space-4);
  border-bottom: var(--border);
  font-size: var(--text-lg);
  font-weight: 700;
}

.body {
  padding: var(--space-4);
