          type="button"
          className={styles["transportBtn"]}
          aria-pressed={isPlaying}
          aria-label="Play"
          onClick={() => {
            transport.play();
          }}
        >
          {"\u25B6"}
        </button>

        <button
          type="button"
          className={styles["transportBtn"]}
          aria-label="Stop"
          onClick={() => {
