import { describe, it, expect, vi } from "vitest";
import type { TrackModel, AudioClipModel } from "@state/track/types";
import {
  renderArrangement,
  type ArrangementViewState,
  type RenderContext,
} from "./arrangement-renderer";

// -- Helpers ------------------------------------------------------------------

type MockCtx = {
  fillRect: ReturnType<typeof vi.fn>;
  strokeRect: ReturnType<typeof vi.fn>;
  fillText: ReturnType<typeof vi.fn>;
  beginPath: ReturnType<typeof vi.fn>;
  moveTo: ReturnType<typeof vi.fn>;
  lineTo: ReturnType<typeof vi.fn>;
  stroke: ReturnType<typeof vi.fn>;
  save: ReturnType<typeof vi.fn>;
  restore: ReturnType<typeof vi.fn>;
  clearRect: ReturnType<typeof vi.fn>;
  rect: ReturnType<typeof vi.fn>;
  clip: ReturnType<typeof vi.fn>;
  measureText: ReturnType<typeof vi.fn>;
  fillStyle: string;
  strokeStyle: string;
  lineWidth: number;
  font: string;
  textBaseline: CanvasTextBaseline;
  textAlign: CanvasTextAlign;
  globalAlpha: number;
};

function createMockCtx(): MockCtx {
  return {
    fillRect: vi.fn(),
    strokeRect: vi.fn(),
    fillText: vi.fn(),
    beginPath: vi.fn(),
    moveTo: vi.fn(),
    lineTo: vi.fn(),
    stroke: vi.fn(),
    save: vi.fn(),
    restore: vi.fn(),
    clearRect: vi.fn(),
    rect: vi.fn(),
    clip: vi.fn(),
    measureText: vi.fn().mockReturnValue({ width: 40 }),
    fillStyle: "",
    strokeStyle: "",
    lineWidth: 0,
    font: "",
    textBaseline: "alphabetic",
    textAlign: "start",
    globalAlpha: 1,
  };
}

function makeTrack(overrides: Partial<TrackModel> = {}): TrackModel {
  return {
    id: "track-1",
    name: "Track 1",
    type: "audio",
    color: "#0066ff",
    muted: false,
    solo: false,
    armed: false,
    soloIsolate: false,
    volume: 1,
    pan: 0,
    clipIds: [],
    ...overrides,
  };
}

function makeClip(overrides: Partial<AudioClipModel> = {}): AudioClipModel {
  return {
    type: "audio",
    id: "clip-1",
    trackId: "track-1",
    sourceId: "src-1",
    startTime: 0,
    sourceOffset: 0,
    duration: 2,
    gain: 1,
    fadeIn: 0,
    fadeOut: 0,
    name: "Clip 1",
    ...overrides,
  };
}

const defaultView: ArrangementViewState = {
  scrollX: 0,
  scrollY: 0,
  pixelsPerSecond: 100,
  trackHeight: 64,
  headerWidth: 160,
};

function makeRenderContext(
  overrides: Partial<Omit<RenderContext, "ctx">> = {},
): { rc: RenderContext; mock: MockCtx } {
  const mock = createMockCtx();
  const rc: RenderContext = {
    ctx: mock as unknown as CanvasRenderingContext2D,
    width: 800,
    height: 400,
    view: defaultView,
    tracks: [],
    clips: {},
    selectedClipIds: [],
    cursorSeconds: 0,
    bpm: 120,
    ...overrides,
  };
  return { rc, mock };
}

// -- Tests --------------------------------------------------------------------

describe("arrangement-renderer", () => {
  describe("renderArrangement", () => {
    it("fills background with gray-900", () => {
      const { rc, mock } = makeRenderContext();
      renderArrangement(rc);
      expect(mock.fillRect).toHaveBeenCalledWith(0, 0, 800, 400);
    });

