2	import { createAutomationScheduler } from "./automation-scheduler";
3	import type {
4	  AutomationLane,
5	  AutomationPoint,
6	  ParameterTarget,
7	} from "./automation-types";
8	
9	function pt(
10	  id: string,
11	  time: number,
12	  value: number,
13	  interpolation: "linear" | "curved" = "linear",
14	  curve = 0,
15	): AutomationPoint {
16	  return { id, time, value, interpolation, curve };
17	}
18	
19	function makeLane(
20	  trackId: string,
21	  target: ParameterTarget,
22	  points: AutomationPoint[],
23	  mode: "read" | "write" | "touch" = "read",
24	): AutomationLane {
25	  return {
26	    id: `lane-${trackId}-${target.type}`,
27	    trackId,
28	    target,
29	    points,
30	    mode,
31	    armed: true,
32	  };
33	}
34	
35	// Minimal AudioParam mock with scheduling methods
36	function mockAudioParam(): {
37	  param: {
38	    value: number;
39	    setValueAtTime: ReturnType<typeof vi.fn>;
40	    linearRampToValueAtTime: ReturnType<typeof vi.fn>;
41	    cancelScheduledValues: ReturnType<typeof vi.fn>;
42	    cancelAndHoldAtTime: ReturnType<typeof vi.fn>;
43	  };
44	} {
45	  const param = {
46	    value: 0,
47	    setValueAtTime: vi.fn(),
48	    linearRampToValueAtTime: vi.fn(),
49	    cancelScheduledValues: vi.fn(),
50	    cancelAndHoldAtTime: vi.fn(),
51	  };
52	  return { param };
53	}
54	
55	describe("AutomationScheduler", () => {
56	  const volumeTarget: ParameterTarget = { type: "mixer", param: "volume" };
57	  const panTarget: ParameterTarget = { type: "mixer", param: "pan" };
58	
59	  let resolveParam: ReturnType<typeof vi.fn>;
60	
61	  beforeEach(() => {
62	    resolveParam = vi.fn();
63	  });
64	
65	  describe("scheduleWindow", () => {
66	    it("schedules value at start of window for lane in read mode", () => {
67	      const { param } = mockAudioParam();
68	      resolveParam.mockReturnValue({ param, range: { min: 0, max: 2 } });
69	
70	      const lane = makeLane("t1", volumeTarget, [
71	        pt("p1", 0, 0, "linear"),
72	        pt("p2", 10, 1, "linear"),
73	      ]);
74	
75	      const scheduler = createAutomationScheduler(resolveParam);
76	      scheduler.scheduleWindow([lane], 0, 1, 0);
77	
78	      // Should schedule values via setValueAtTime
79	      expect(param.setValueAtTime).toHaveBeenCalled();
80	    });
81	
82	    it("does not schedule if lane is not armed", () => {
83	      const { param } = mockAudioParam();
84	      resolveParam.mockReturnValue({ param, range: { min: 0, max: 2 } });
85	
86	      const lane: AutomationLane = {
87	        ...makeLane("t1", volumeTarget, [pt("p1", 0, 0.5)]),
88	        armed: false,
89	      };
90	
91	      const scheduler = createAutomationScheduler(resolveParam);
92	      scheduler.scheduleWindow([lane], 0, 1, 0);
93	
94	      expect(param.setValueAtTime).not.toHaveBeenCalled();
95	    });
96	
97	    it("does not schedule if lane has no points", () => {
98	      const { param } = mockAudioParam();
99	      resolveParam.mockReturnValue({ param, range: { min: 0, max: 2 } });
100	
101	      const lane = makeLane("t1", volumeTarget, []);
102	      const scheduler = createAutomationScheduler(resolveParam);
103	      scheduler.scheduleWindow([lane], 0, 1, 0);
104	
105	      expect(param.setValueAtTime).not.toHaveBeenCalled();
106	    });
107	
108	    it("does not schedule in write mode (write mode records, not plays)", () => {
109	      const { param } = mockAudioParam();
110	      resolveParam.mockReturnValue({ param, range: { min: 0, max: 2 } });
111	
112	      const lane = makeLane("t1", volumeTarget, [pt("p1", 0, 0.5)], "write");
113	
114	      const scheduler = createAutomationScheduler(resolveParam);
115	      scheduler.scheduleWindow([lane], 0, 1, 0);
116	
117	      expect(param.setValueAtTime).not.toHaveBeenCalled();
118	    });
119	
120	    it("handles linear interpolation across a scheduling window", () => {
121	      const { param } = mockAudioParam();
122	      resolveParam.mockReturnValue({ param, range: { min: 0, max: 1 } });
123	
124	      const lane = makeLane("t1", volumeTarget, [
125	        pt("p1", 0, 0, "linear"),
126	        pt("p2", 10, 1, "linear"),
127	      ]);
128	
129	      const scheduler = createAutomationScheduler(resolveParam);
130	      // Window from t=0 to t=1, timeOffset=100 (arrangement -> audioCtx)
131	      scheduler.scheduleWindow([lane], 100, 101, 100);
132	
133	      // Should have scheduled a value at the window start
134	      expect(param.setValueAtTime).toHaveBeenCalled();
135	      const call = param.setValueAtTime.mock.calls[0] as [number, number];
136	      // Value at t=0 is 0 (normalized) -> denormalized to range 0..1 = 0
137	      expect(call[0]).toBeCloseTo(0, 2);
138	    });
139	
140	    it("schedules for pan with range -1..1", () => {
141	      const { param } = mockAudioParam();
142	      resolveParam.mockReturnValue({ param, range: { min: -1, max: 1 } });
143	
144	      const lane = makeLane("t1", panTarget, [pt("p1", 0, 0.5)]);
145	
146	      const scheduler = createAutomationScheduler(resolveParam);
147	      scheduler.scheduleWindow([lane], 0, 1, 0);
148	
149	      expect(param.setValueAtTime).toHaveBeenCalled();
150	      // 0.5 normalized with range -1..1 = 0
151	      const call = param.setValueAtTime.mock.calls[0] as [number, number];
152	      expect(call[0]).toBeCloseTo(0, 2);
153	    });
154	
155	    it("skips lanes where resolveParam returns undefined", () => {
156	      resolveParam.mockReturnValue(undefined);
157	
158	      const lane = makeLane("t1", volumeTarget, [pt("p1", 0, 0.5)]);
159	      const scheduler = createAutomationScheduler(resolveParam);
160	
161	      // Should not throw
162	      expect(() => {
163	        scheduler.scheduleWindow([lane], 0, 1, 0);
164	      }).not.toThrow();
165	    });
166	
167	    it("uses linearRamp when a segment spans the scheduling window", () => {
168	      const { param } = mockAudioParam();
169	      resolveParam.mockReturnValue({ param, range: { min: 0, max: 1 } });
170	
171	      const lane = makeLane("t1", volumeTarget, [
172	        pt("p1", 0, 0, "linear"),
173	        pt("p2", 10, 1, "linear"),
174	      ]);
175	
176	      const scheduler = createAutomationScheduler(resolveParam);
177	      // Window: arrangement t=0..1 -> audioCtx t=50..51
178	      scheduler.scheduleWindow([lane], 50, 51, 50);
179	
180	      expect(param.setValueAtTime).toHaveBeenCalled();
181	      expect(param.linearRampToValueAtTime).toHaveBeenCalled();
182	    });
183	
184	    it("schedules exact breakpoints within the window", () => {
185	      const { param } = mockAudioParam();
186	      resolveParam.mockReturnValue({ param, range: { min: 0, max: 1 } });
187	
