    // At t=2, normalized value is 0.2 (linear interp 2/10), denormalized = 0.2 * 2 = 0.4
    const endRamps = param.linearRampToValueAtTime.mock.calls as [
      number,
      number,
    ][];
    const endRamp = endRamps[endRamps.length - 1];
    expect(endRamp?.[0]).toBeCloseTo(0.4, 2);
    expect(endRamp?.[1]).toBe(2); // window end
  });

  it("ignores unarmed lanes", () => {
    const store = useAutomationStore.getState();
    store.addLane("track-1", { type: "mixer", param: "volume" });
    const lane = useAutomationStore.getState().getLanes("track-1")[0];
    expect(lane).toBeDefined();

    store.addPoint("track-1", lane!.id, {
      id: "p1",
      time: 0,
      value: 0.5,
      interpolation: "linear",
      curve: 0,
    });

    // Disarm the lane
    store.setArmed("track-1", lane!.id, false);

    const param = mockAudioParam();
    const resolver: ParamResolver = (l) => {
      if (l.target.type === "mixer" && l.target.param === "volume") {
        return { param, range: { min: 0, max: 2 } };
      }
      return undefined;
    };

    const scheduler = createAutomationScheduler(resolver);
    const lanes = useAutomationStore.getState().getLanes("track-1");
    scheduler.scheduleWindow(lanes, 0, 1, 0);

    // Should NOT schedule anything because lane is disarmed
    expect(param.setValueAtTime).not.toHaveBeenCalled();
  });

  it("handles pan automation with -1..1 range", () => {
    const store = useAutomationStore.getState();
    store.addLane("track-1", { type: "mixer", param: "pan" });
    const lane = useAutomationStore.getState().getLanes("track-1")[0];
    expect(lane).toBeDefined();

    // Center pan (0.5 normalized -> 0.0 actual)
    store.addPoint("track-1", lane!.id, {
      id: "p1",
      time: 0,
      value: 0.5,
      interpolation: "linear",
      curve: 0,
    });

    const param = mockAudioParam();
    const resolver: ParamResolver = (l) => {
      if (l.target.type === "mixer" && l.target.param === "pan") {
        return { param, range: { min: -1, max: 1 } };
      }
      return undefined;
    };

    const scheduler = createAutomationScheduler(resolver);
    const lanes = useAutomationStore.getState().getLanes("track-1");
    scheduler.scheduleWindow(lanes, 0, 1, 0);

    expect(param.setValueAtTime).toHaveBeenCalled();
    const startCall = param.setValueAtTime.mock.calls[0] as [number, number];
    // 0.5 normalized with range -1..1 = -1 + 0.5 * 2 = 0.0
    expect(startCall[0]).toBeCloseTo(0.0, 2);
  });

  it("cleans up with cancelAll", () => {
    const store = useAutomationStore.getState();
    store.addLane("track-1", { type: "mixer", param: "volume" });
    const lane = useAutomationStore.getState().getLanes("track-1")[0];
    expect(lane).toBeDefined();

    store.addPoint("track-1", lane!.id, {
      id: "p1",
      time: 0,
      value: 0.5,
      interpolation: "linear",
      curve: 0,
    });

    const param = mockAudioParam();
    const resolver: ParamResolver = () => ({
      param,
      range: { min: 0, max: 2 },
    });

    const scheduler = createAutomationScheduler(resolver);
    const lanes = useAutomationStore.getState().getLanes("track-1");
    scheduler.scheduleWindow(lanes, 0, 1, 0);
    scheduler.cancelAll();

    expect(param.cancelScheduledValues).toHaveBeenCalled();
  });
});

import { describe, it, expect, vi, beforeAll, beforeEach } from "vitest";
import { render, screen, fireEvent, waitFor } from "@testing-library/react";
import { BounceDialog } from "./BounceDialog";

beforeAll(() => {
  HTMLDialogElement.prototype.showModal = vi.fn();
  HTMLDialogElement.prototype.close = vi.fn();
});

// Mock stores
vi.mock("@state/store", () => ({
  useDawStore: Object.assign(
    (selector: (s: Record<string, unknown>) => unknown) =>
      selector({
        tracks: [],
        clips: {},
        bpm: 120,
        masterVolume: 1,
        loopStart: 0,
        loopEnd: 10,
      }),
    {
      getState: () => ({
        tracks: [],
        clips: {},
        bpm: 120,
        masterVolume: 1,
        loopStart: 0,
        loopEnd: 10,
      }),
    },
  ),
}));

vi.mock("@state/automation", () => ({
  useAutomationStore: Object.assign(
    (selector: (s: Record<string, unknown>) => unknown) =>
      selector({ lanes: {} }),
    {
      getState: () => ({ lanes: {} }),
    },
  ),
}));

const mockCancel = vi.fn();
let bounceResolve: (() => void) | null = null;

vi.mock("@audio/bounce", () => ({
  createBounceEngine: () => ({
    bounce: async function* () {
      yield {
        phase: "rendering" as const,
        progress: 0.5,
        renderedSeconds: 5,
        totalSeconds: 10,
      };
      // Pause here so tests can observe the progress bar
      await new Promise<void>((resolve) => {
        bounceResolve = resolve;
      });
      return {
        blob: new Blob(["wav"], { type: "audio/wav" }),
        duration: 10,
        sampleRate: 48000,
        channels: 2,
      };
    },
    cancel: mockCancel,
  }),
}));

describe("BounceDialog", () => {
  const onClose = vi.fn();

  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("renders nothing when closed", () => {
    render(<BounceDialog open={false} onClose={onClose} />);
    expect(screen.queryByText("Export Audio")).not.toBeInTheDocument();
  });

  it("shows title and format info when open", () => {
    render(<BounceDialog open={true} onClose={onClose} />);
    expect(screen.getByText("Export Audio")).toBeInTheDocument();
    expect(screen.getByText(/WAV/)).toBeInTheDocument();
    expect(screen.getByText(/48kHz/)).toBeInTheDocument();
    expect(screen.getByText(/32-bit/)).toBeInTheDocument();
  });

  it("has Full Session and Loop Region range options", () => {
    render(<BounceDialog open={true} onClose={onClose} />);
    expect(screen.getByLabelText("Full Session")).toBeInTheDocument();
    expect(screen.getByLabelText("Loop Region")).toBeInTheDocument();
  });

  it("defaults to Full Session range", () => {
    render(<BounceDialog open={true} onClose={onClose} />);
    const radio = screen.getByLabelText("Full Session");
    expect(radio.checked).toBe(true);
  });

  it("has a Bounce button", () => {
    render(<BounceDialog open={true} onClose={onClose} />);
    expect(
      screen.getByRole("button", { name: /bounce/i }),
    ).toBeInTheDocument();
  });

  it("has a Cancel button that calls onClose", () => {
    render(<BounceDialog open={true} onClose={onClose} />);
    fireEvent.click(screen.getByRole("button", { name: /cancel/i }));
    expect(onClose).toHaveBeenCalledTimes(1);
  });

  it("shows progress bar during bounce", async () => {
    bounceResolve = null;
    render(<BounceDialog open={true} onClose={onClose} />);
    fireEvent.click(screen.getByRole("button", { name: /bounce/i }));
    await waitFor(() => {
      expect(screen.getByRole("progressbar")).toBeInTheDocument();
    });
    // Allow the generator to finish so no leaked promises
    bounceResolve?.();
  });
});
